---
import ArrowRightIcon from "@lucide/astro/icons/arrow-right"

import { cn } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Icon } from "@/components/ui/icon"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  badge?: string
  title: string
  description?: string
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  services: {
    icon?: string
    title: string
    description: string
    href?: string
  }[]
}

const {
  class: className,
  badge,
  title,
  description,
  buttons,
  services,
} = Astro.props
---

<Section class={cn("", className)}>
  <SectionContainer class="gap-12">
    <div class="mx-auto max-w-2xl text-center">
      {badge && <Badge variant="secondary">{badge}</Badge>}
      <h2
        class="mt-4 text-3xl font-semibold tracking-tight text-balance sm:text-4xl"
      >
        {title}
      </h2>
      {
        description && (
          <p class="text-muted-foreground mt-4 text-base leading-relaxed text-balance">
            {description}
          </p>
        )
      }
      {
        buttons?.length && (
          <div class="mt-6 flex flex-wrap justify-center gap-3">
            {buttons.map(({ href, label, ...button }) => (
              <Button as="a" href={href} variant={button.variant}>
                {label}
              </Button>
            ))}
          </div>
        )
      }
    </div>
    <div
      class="ring-foreground/10 bg-border grid gap-px overflow-hidden rounded-xl ring-1 ring-inset sm:grid-cols-2 lg:grid-cols-4"
    >
      {
        services.map((service) => (
          <div class="bg-background group/service hover:bg-accent/30 relative flex flex-col gap-4 p-7 transition-colors">
            <div class="bg-primary/10 text-primary ring-primary/15 flex size-10 items-center justify-center rounded-lg ring-1 transition-transform ring-inset group-hover/service:scale-105">
              <Icon name={service.icon ?? "layout-grid"} class="size-5" />
            </div>
            <h3 class="text-base font-medium tracking-tight">
              {service.title}
            </h3>
            <p class="text-muted-foreground text-sm leading-relaxed">
              {service.description}
            </p>
            {service.href && (
              <a
                href={service.href}
                class="text-primary mt-auto inline-flex items-center gap-1.5 text-sm font-medium"
              >
                Learn more
                <ArrowRightIcon class="size-3.5 transition-transform group-hover/service:translate-x-1" />
              </a>
            )}
          </div>
        ))
      }
    </div>
  </SectionContainer>
</Section>
